import { Box } from '@semparar/design-system-app';
import { Image } from 'react-native';
import { Text } from '@semparar/design-system-app/fintech';
import React from 'react';
import { Animated } from 'react-native';
import arrow from '../../../assets/images/arrow.png';
import { AnimationArrowsViewProps } from './Models';
import { Container } from './styles';

const AnimationArrowsView = ({
  arrow1Move,
  arrow1Fade,
  arrow2Move,
  arrow2Fade,
  arrow3Move,
  arrow3Fade,
}: AnimationArrowsViewProps) => {
  return (
    <Container testID="AnimationArrowsView">
      <Box
        justify="center"
        align="center"
        width="100%"
        overflow="hidden"
        height={175}
      >
        <Box direction justify="center">
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateX: -35 }, { translateY: arrow1Move }],
                opacity: arrow1Fade,
              },
            ]}
          >
            <Image style={{ height: 41, width: 30 }} source={arrow} />
          </Animated.View>
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateY: arrow2Move }],
                opacity: arrow2Fade,
              },
            ]}
          >
            <Image style={{ height: 41, width: 30 }} source={arrow} />
          </Animated.View>
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateX: 30 }, { translateY: arrow3Move }],
                opacity: arrow3Fade,
              },
            ]}
          >
            <Image style={{ height: 41, width: 30 }} source={arrow} />
          </Animated.View>
        </Box>
      </Box>
      <Text align="center" mt="middle" type="subtitleLarger">
        Estamos carregando suas informações...
      </Text>
    </Container>
  );
};

export default AnimationArrowsView;

